import React, { useState, useRef, useEffect } from 'react';
import NavBar from '../../components/NavBar/NavBar';
import Waveform from '../../components/Waveform/Waveform';
import './Record.css';

function Share({ audioBlob, duration = 0, onShare, onNew }) {
  const [isPlaying, setIsPlaying] = useState(false);
  const [time, setTime] = useState(0);
  const audioRef = useRef(null);
  const intervalRef = useRef(null);

  useEffect(() => {
    if (audioBlob) {
      const url = URL.createObjectURL(audioBlob);
      audioRef.current = new Audio(url);
      audioRef.current.onended = () => {
        setIsPlaying(false);
        clearInterval(intervalRef.current);
      };
      return () => {
        URL.revokeObjectURL(url);
        if (audioRef.current) audioRef.current.pause();
        clearInterval(intervalRef.current);
      };
    }
  }, [audioBlob]);

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
      clearInterval(intervalRef.current);
      setIsPlaying(false);
    } else {
      audioRef.current.play();
      setIsPlaying(true);
      intervalRef.current = setInterval(() => {
        setTime(Math.floor(audioRef.current.currentTime));
      }, 200);
    }
  };

  const skip = (amt) => {
    if (!audioRef.current) return;
    const newTime = Math.max(0, Math.min(audioRef.current.currentTime + amt, audioRef.current.duration || duration));
    audioRef.current.currentTime = newTime;
    setTime(Math.floor(newTime));
  };

  const formatTime = (s) => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;

  return (
    <div className="screen">
      <div className="screen-content">
        <div className="status-badge saved">
          ✓ Recording Saved
        </div>

        <div className="timer">
          {formatTime(time)}
          <span className="duration"> / {formatTime(duration)}</span>
        </div>

        <Waveform mode="static" />

        <div className="playback-controls">
          <button className="btn btn-skip" onClick={() => skip(-5)}>-5s</button>
          <button className="btn btn-play" onClick={togglePlay}>
            {isPlaying ? '⏸' : '▶'}
          </button>
          <button className="btn btn-skip" onClick={() => skip(5)}>+5s</button>
        </div>

        <div className="btn-row">
          <button className="btn btn-share" onClick={onShare}>
            ↗ Share
          </button>
          <button className="btn btn-new" onClick={onNew}>
            + New
          </button>
        </div>
      </div>
      <NavBar active="record" />
    </div>
  );
}

export default Share;
